VALUES
  ('police-f3743df6-moex-00080', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲校實驗室存放 30 桶未標示之廢溶劑，經主管機關稽查人員現場認定有爆燃危險，立即封緘並 貼封條，並扣留樣品，以利事後之裁處。甲校質疑稽查人員「未出示證件，有程序瑕疵」。下列 敘述何者正確？', '["稽查人員得逕行封緘，不必出示證件", "稽查人員應先出示證件並告知違反之法規", "扣留僅限24 小時，逾期視為無效", "立即封緘並貼封條時，甲校不得異議，僅能待裁處後再救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00081', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '農民甲為預防山豬竊食，在果園架設高壓電網，因未申報而觸法，甲被主管機關裁處罰鍰並勒令 拆除。甲抗辯屬保護財產之正當防衛。下列敘述何者正確？', '["刑法正當防衛阻卻違法理論，並不適用於行政罰", "甲之行為屬正當防衛過當，得減輕或免除其處罰", "甲之行為不符合正當防衛，仍應受處罰", "甲之行為屬正當防衛行為，不予處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00082', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '主管機關於民國109年3月15日查報乙之違建，之後因進行行政調查、復驗，遲至113年5月 12日始作成罰鍰處分，乙主張該處分違法。下列敘述何者正確？', '["裁處權已因3年經過而消滅", "裁處權時效為5年，仍得裁處", "裁處權因行政調查而中斷時效", "裁處權不適用時效規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00083', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於行政執行，下列何者非屬直接強制之方法？', '["封閉住宅", "拘提管收", "斷水斷電", "註銷證照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00084', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲因積欠健保費移送行政執行，法務部行政執行署A分署（下稱執行機關）扣押甲之銀行存款新 臺幣20萬元時，第三人乙主張該存款為其所有，僅係由甲代管。下列敘述何者正確？', '["執行機關應即停止扣押，待法院確認所有權後再行執行", "執行機關應先暫緩執行，並通知甲、乙調解", "乙得在執行程序終結前，向執行機關聲明異議", "執行機關應依職權撤銷扣押或以調解方式處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00085', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '在制定法規命令的過程中，下列何者非人民得參與之事項？', '["提議請求制定法規命令", "參與聽證程序", "於所定期間內向行政機關陳述意見", "請求送交立法院審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00086', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列何種行政爭訟事件，非以地方行政法院作為第一審之管轄法院？', '["甲為外國人，因遭強制出境而被內政部移民署收容", "乙收受另補繳所得稅新臺幣100萬元之處分", "丙未得許可將非屬汽車的起重機行駛於道路，被裁罰新臺幣3千元罰鍰", "丁為任職於A市工務局之公務人員，年終考績被考列乙等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00087', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲縣政府對乙作成處分後，乙不服提起訴願。下列敘述何者正確？', '["乙只能向甲縣政府申請停止執行", "因提起訴願，甲縣政府應先停止執行", "行政救濟確定前，僅甲縣政府得依職權停止執行", "甲縣政府原則上不因提起訴願而停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00088', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲於民國114年2月14日向乙縣政府申請農地使用許可，惟乙縣政府屆滿2個月後未為任何表 示，甲直至114年8月1日才提起消極不作為訴願。下列敘述何者正確？', '["訴願已逾訴願法第14條所定提起訴願之期間，應不受理", "類推適用訴願法第14條所定提起訴願期間，訴願應不受理", "本件無提起訴願期間限制，甲得隨時提起訴願", "甲得申請回復原狀後，再提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00089', 'police-f3743df6', 'police-f3743df6-moex-114-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲訴願書錯誤寄送至原處分機關之下級機關，下級機關於5月10日收受，於5月11日即移送於 原處分機關。下列敘述何者正確？', '["甲提起訴願錯誤，原處分機關應不受理", "以5月11日送達原處分機關之日，作為提起訴願之日", "以5月10日下級機關收受之日，視為提起訴願之日", "應自通知訴願人已將訴願書移送至原處分機關之日，視為自始提起訴願之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "888dec08f6fb", "answer_pdf_sha1": "42e70242ba91", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
